// OAuth 2.0 Client
class OAuthClient {
  constructor(clientId, clientSecret, authUrl, tokenUrl, redirectUri) {
    this.clientId = clientId;
    this.clientSecret = clientSecret;
    this.authUrl = authUrl;
    this.tokenUrl = tokenUrl;
    this.redirectUri = redirectUri;
    this.accessToken = localStorage.getItem('accessToken');
    this.refreshToken = localStorage.getItem('refreshToken');
    this.tokenExpiry = localStorage.getItem('tokenExpiry');
  }

  async authorize() {
    const authEndpoint = `${this.authUrl}?response_type=code&client_id=${encodeURIComponent(this.clientId)}&redirect_uri=${encodeURIComponent(this.redirectUri)}`;
    window.location = authEndpoint;
  }

  async handleRedirect() {
    const params = new URLSearchParams(window.location.search);
    const code = params.get('code');
    if (code) {
      await this.exchangeCodeForToken(code);
      window.history.replaceState({}, document.title, window.location.pathname);
    }
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri,
        client_id: this.clientId,
        client_secret: this.clientSecret,
      }),
    });
    const data = await response.json();
    this.setTokens(data.access_token, data.refresh_token, data.expires_in);
  }

  setTokens(accessToken, refreshToken, expiresIn) {
    this.accessToken = accessToken;
    this.refreshToken = refreshToken;
    this.tokenExpiry = Date.now() + expiresIn * 1000;
    localStorage.setItem('accessToken', accessToken);
    localStorage.setItem('refreshToken', refreshToken);
    localStorage.setItem('tokenExpiry', this.tokenExpiry);
  }

  async refreshAccessToken() {
    if (!this.refreshToken) throw new Error('No refresh token available');
    const response = await fetch(this.tokenUrl, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
      },
      body: new URLSearchParams({
        grant_type: 'refresh_token',
        refresh_token: this.refreshToken,
        client_id: this.clientId,
        client_secret: this.clientSecret,
      }),
    });
    const data = await response.json();
    this.setTokens(data.access_token, data.refresh_token, data.expires_in);
  }

  async getAccessToken() {
    if (Date.now() > this.tokenExpiry) {
      await this.refreshAccessToken();
    }
    return this.accessToken;
  }
}

